import os
import sys
from PIL import Image
from google.cloud import storage
import subprocess

def process_image(event, context):
    bucket_name = event['bucket']
    src_blob = storage.Blob(event['name'], bucket=storage.Client().get_bucket(bucket_name))
    dst_blob_name = os.path.basename(event['name']) + '.' + event['contentType'].split('/')[-1]
    dst_blob = storage.Blob(dst_blob_name, bucket=storage.Client().get_bucket(bucket_name))

    metadata = src_blob.metadata
    command = ['/usr/bin/convert', src_blob.name, dst_blob_name]

    if 'options' in metadata:
        options = metadata['options']
        command += options.split(' ')

    subprocess.call(command)
    dst_blob.upload_from_string(src_blob.download_as_string())